{"content": "import { useState } from 'react'
import PortfolioInput from './components/PortfolioInput'
import Dashboard from './components/Dashboard'
import Report from './components/Report'
import Education from './components/Education'
import './App.css'

function App() {
  const [page, setPage] = useState('input')  // input | dashboard | report | education
  const [portfolio, setPortfolio] = useState({ funds: [], cryptos: [] })
  const [analysis, setAnalysis] = useState(null)
  const [report, setReport] = useState(null)

  return (
    <div className="app">
      <header className="app-header">
        <div className="logo" onClick={() => setPage('input')}>
          <span className="logo-icon">💰</span>
          <span className="logo-text">我的钱还好吗？</span>
        </div>
        <nav className="nav">
          <button className={page === 'input' ? 'active' : ''} onClick={() => setPage('input')}>录入持仓</button>
          <button className={page === 'dashboard' ? 'active' : ''} onClick={() => setPage('dashboard')} disabled={!analysis}>数据看板</button>
          <button className={page === 'report' ? 'active' : ''} onClick={() => setPage('report')} disabled={!report}>AI 体检</button>
          <button className={page === 'education' ? 'active' : ''} onClick={() => setPage('education')}>学一学</button>
        </nav>
      </header>

      <main className="main-content">
        {page === 'input' && (
          <PortfolioInput 
            portfolio={portfolio} 
            setPortfolio={setPortfolio}
            onAnalyze={async (p) => {
              setAnalysis({ loading: true })
              setPage('dashboard')
              try {
                const { analyzePortfolio } = await import('./api')
                const data = await analyzePortfolio(p)
                setAnalysis(data)
              } catch (e) {
                setAnalysis({ error: e.message })
              }
            }}
            onReport={async (p) => {
              setReport({ loading: true })
              setPage('report')
              try {
                const { generateReport } = await import('./api')
                const data = await generateReport(p)
                setReport(data)
              } catch (e) {
                setReport({ error: e.message })
              }
            }}
          />
        )}
        {page === 'dashboard' && <Dashboard analysis={analysis} />}
        {page === 'report' && <Report report={report} />}
        {page === 'education' && <Education />}
      </main>

      <footer className="app-footer">
        <p>💡 投资有风险，入市需谨慎。本工具仅供学习参考，不构成投资建议。</p>
      </footer>
    </div>
  )
}

export default App
