  flex-direction: column;
  gap: 4px;
}

.holding-name {
  font-weight: 600;
  font-size: 15px;
}

.holding-detail {
  color: var(--text-dim);
  font-size: 13px;
}

.holding-value {
  font-weight: 600;
  font-size: 15px;
}

/* Stats */
.stats-grid {
  display: grid;
  grid-template-columns: repeat(2, 1fr);
  gap: 12px;
}

.stat-card {
  background: var(--bg);
  border-radius: 12px;
  padding: 16px;
  text-align: center;
}

.stat-value {
  font-size: 24px;
  font-weight: 700;
  margin-bottom: 4px;
