const QUICK_FUNDS = [
  { code: '110011', name: '易方达中小盘' },
  { code: '161725', name: '招商中证白酒' },
  { code: '005827', name: '易方达蓝筹精选' },
  { code: '003834', name: '华夏能源革新' },
  { code: '001938', name: '中欧时代先锋' },
]

const QUICK_CRYPTOS = [
  { symbol: 'BTC', name: '比特币' },
  { symbol: 'ETH', name: '以太坊' },
  { symbol: 'SOL', name: 'Solana' },
  { symbol: 'DOGE', name: '狗狗币' },
]

export default function PortfolioInput({ portfolio, setPortfolio, onAnalyze, onReport }) {
  const [fundCode, setFundCode] = useState('')
  const [fundAmount, setFundAmount] = useState('')
  const [cryptoSymbol, setCryptoSymbol] = useState('')
  const [cryptoAmount, setCryptoAmount] = useState('')

  const addFund = (code, name) => {
    const c = code || fundCode
    const a = fundAmount || '1000'
    if (!c) return
    setPortfolio(p => ({
      ...p,
      funds: [...p.funds, { code: c, amount: parseFloat(a), name: name || c }]
    }))
    setFundCode('')
    setFundAmount('')
  }

  const addCrypto = (symbol, name) => {
    const s = symbol || cryptoSymbol
    const a = cryptoAmount || '0.1'
    if (!s) return
    setPortfolio(p => ({
      ...p,
      cryptos: [...p.cryptos, { symbol: s.toUpperCase(), amount: parseFloat(a), name: name || s }]
    }))
    setCryptoSymbol('')
    setCryptoAmount('')
  }

  const removeFund = (index) => {
    setPortfolio(p => ({
      ...p,
      funds: p.funds.filter((_, i) => i !== index)
    }))
  }

  const removeCrypto = (index) => {
    setPortfolio(p => ({
      ...p,
      cryptos: p.cryptos.filter((_, i) => i !== index)
    }))
  }

  const hasData = portfolio.funds.length > 0 || portfolio.cryptos.length > 0

  return (
    <div>
      <div className="card">
        <div className="card-title">📈 录入你的持仓</div>
        <p style={{ color: 'var(--text-dim)', fontSize: '14px', marginBottom: '20px' }}>
          输入你买的基金和加密货币，我们帮你看看它们的情况
        </p>

        {/* 基金录入 */}
        <div className="section-title">💵 基金</div>
        <div className="input-group">
          <input
            placeholder="基金代码，如 110011"
            value={fundCode}
            onChange={e => setFundCode(e.target.value)}
          />
          <input
            type="number"
            placeholder="持有金额（元）"
            value={fundAmount}
            onChange={e => setFundAmount(e.target.value)}
            style={{ maxWidth: '160px' }}
          />
          <button className="btn btn-primary" onClick={() => addFund()}>添加</button>
        </div>
        <div className="quick-add">
          {QUICK_FUNDS.map(f => (
            <button key={f.code} onClick={() => addFund(f.code, f.name)}>
              + {f.name}
            </button>
          ))}
        </div>

        {/* 已添加的基金 */}
        {portfolio.funds.length > 0 && (
          <div style={{ marginTop: '16px' }}>
            {portfolio.funds.map((f, i) => (
              <div className="holding-item" key={i}>
                <div className="holding-info">
                  <span className="holding-name">📊 {f.name || f.code}</span>
                  <span className="holding-detail">代码 {f.code}</span>
                </div>
                <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                  <span className="holding-value">¥{f.amount.toLocaleString()}</span>
                  <button className="btn btn-danger" onClick={() => removeFund(i)} style={{ padding: '4px 8px', fontSize: '12px' }}>✕</button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      <div className="card">
        <div className="card-title">🪙 加密货币</div>

        <div className="section-title">币种</div>
        <div className="input-group">
          <input
            placeholder="币种，如 BTC, ETH"
            value={cryptoSymbol}
            onChange={e => setCryptoSymbol(e.target.value)}
          />
          <input
            type="number"
            step="0.01"
            placeholder="持有数量"
            value={cryptoAmount}
            onChange={e => setCryptoAmount(e.target.value)}
            style={{ maxWidth: '160px' }}
          />
          <button className="btn btn-primary" onClick={() => addCrypto()}>添加</button>
        </div>
        <div className="quick-add">
          {QUICK_CRYPTOS.map(c => (
            <button key={c.symbol} onClick={() => addCrypto(c.symbol, c.name)}>
              + {c.name} ({c.symbol})
            </button>
          ))}
        </div>

        {/* 已添加的币 */}
        {portfolio.cryptos.length > 0 && (
          <div style={{ marginTop: '16px' }}>
            {portfolio.cryptos.map((c, i) => (
              <div className="holding-item" key={i}>
                <div className="holding-info">
                  <span className="holding-name">🪙 {c.name || c.symbol}</span>
                  <span className="holding-detail">{c.symbol}</span>
                </div>
                <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
                  <span className="holding-value">{c.amount} {c.symbol}</span>
                  <button className="btn btn-danger" onClick={() => removeCrypto(i)} style={{ padding: '4px 8px', fontSize: '12px' }}>✕</button>
                </div>
              </div>
            ))}
          </div>
        )}
      </div>

      {/* 操作按钮 */}
      {hasData && (
        <div className="actions">
          <button className="btn btn-primary" onClick={() => onAnalyze(portfolio)}>
            📊 看数据
          </button>
          <button className="btn btn-secondary" onClick={() => onReport(portfolio)}>
            🤖 生成 AI 体检报告
          </button>
        </div>
      )}
    </div>
  )
}
