import { explainConcept } from '../api'

const QUESTIONS = [
  {
    q: '什么是基金？',
    concept: '基金是什么，用最简单的话解释给完全不懂的人',
  },
  {
    q: '余额宝到底是什么？',
    concept: '余额宝是什么，和银行存款有什么区别',
  },
  {
    q: '什么是净值？',
    concept: '基金的净值是什么意思，怎么理解净值的涨跌',
  },
  {
    q: '什么是定投？',
    concept: '基金定投是什么，为什么适合新手',
  },
  {
    q: '什么是波动率？',
    concept: '投资中的波动率是什么，怎么看',
  },
  {
    q: '比特币是什么？',
    concept: '比特币是什么，为什么这么多人关注',
  },
  {
    q: '什么是区块链？',
    concept: '区块链是什么，用生活中的例子解释',
  },
  {
    q: '风险承受能力是什么？',
    concept: '投资中的风险承受能力是什么，怎么评估',
  },
  {
    q: '什么是分散投资？',
    concept: '不要把鸡蛋放在一个篮子里是什么意思',
  },
  {
    q: '什么是 ESG 投资？',
    concept: 'ESG 投资是什么，为什么越来越多人关注',
  },
]

export default function Education() {
  const [answers, setAnswers] = useState({})
  const [loading, setLoading] = useState({})

  const handleExplain = async (index, concept) => {
    if (answers[index]) {
      // Toggle visibility
      setAnswers(prev => ({ ...prev, [index]: prev[index] === '__hidden__' ? prev[index + '_text'] : '__hidden__' }))
      return
    }

    setLoading(prev => ({ ...prev, [index]: true }))
    try {
      const data = await explainConcept(concept)
      setAnswers(prev => ({ ...prev, [index]: data.explanation, [index + '_text']: data.explanation }))
    } catch (e) {
      setAnswers(prev => ({ ...prev, [index]: '暂时无法解释，稍后再试试～' }))
    }
    setLoading(prev => ({ ...prev, [index]: false }))
  }

  return (
    <div>
      <div className="card">
        <div className="card-title">📚 投资小课堂</div>
        <p style={{ color: 'var(--text-dim)', fontSize: '14px', marginBottom: '20px' }}>
          不懂的概念点一下，AI 帮你用大白话解释
        </p>

        <div className="education-grid">
          {QUESTIONS.map((item, i) => (
            <div 
              className="edu-item" 
              key={i}
              onClick={() => handleExplain(i, item.concept)}
            >
              <div className="edu-question">
                {answers[i] && answers[i] !== '__hidden__' ? '💡' : '❓'} {item.q}
              </div>
              {loading[i] && (
                <div className="edu-answer loading">思考中...</div>
              )}
              {answers[i] && answers[i] !== '__hidden__' && !loading[i] && (
                <div className="edu-answer">{answers[i]}</div>
              )}
            </div>
          ))}
        </div>
      </div>

      <div className="card">
        <div className="card-title">🎯 新手入门路径</div>
        <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
          {[
            { step: 1, title: '认识你的钱', desc: '先搞清楚你把钱放在了哪里', done: true },
            { step: 2, title: '看懂体检报告', desc: '了解你的投资组合状况', done: false },
            { step: 3, title: '学习基础概念', desc: '点一点上面的问题，涨知识', done: false },
            { step: 4, title: '开始行动', desc: '设定目标，制定计划', done: false },
          ].map(item => (
            <div className="holding-item" key={item.step}>
              <div className="holding-info">
                <span className="holding-name">
                  {item.done ? '✅' : '⬜'} Step {item.step}: {item.title}
                </span>
                <span className="holding-detail">{item.desc}</span>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  )
}
